'use client';

import Image from 'next/image';
import { useStore } from '../lib/store';

export default function ProfileCard({ member }) {
  const { transactions } = useStore();

  const contributed = transactions
    ?.filter((t) => t.type === 'donation' && t.donorName === member.name)
    .reduce((sum, t) => sum + (Number(t.amount) || 0), 0) || 0;

  const received = transactions
    ?.filter((t) => t.type === 'donation' && t.receiverName === member.name)
    .reduce((sum, t) => sum + (Number(t.amount) || 0), 0) || member.totalReceived || 0;

  const avatarFallback = `https://i.pravatar.cc/200?u=${encodeURIComponent(member.name || 'user')}`;

  return (
    <div className="bg-white rounded-3xl shadow-xl p-6 md:p-8 text-center hover:shadow-2xl transition-all duration-300 transform hover:-translate-y-1 border border-gray-100">
      <div className="relative w-32 h-32 md:w-40 md:h-40 mx-auto mb-6">
        <Image
          src={member.avatar || avatarFallback}
          alt={member.name || 'সদস্য'}
          fill
          className="rounded-full object-cover border-4 border-indigo-400 shadow-lg"
          sizes="(max-width: 768px) 128px, 160px"
          onError={(e) => {
            e.target.src = avatarFallback;
          }}
        />
      </div>

      <h3 className="text-xl md:text-2xl font-bold text-gray-900 mb-4">
        {member.name || 'নামহীন'}
      </h3>

      <div className="grid grid-cols-2 gap-6 mb-6">
        <div className="bg-emerald-50/60 p-4 rounded-2xl border border-emerald-100">
          <p className="text-2xl md:text-3xl font-bold text-emerald-600">
            ৳ {contributed.toLocaleString('bn-BD')}
          </p>
          <p className="text-sm text-gray-600 mt-1 font-medium">দান করেছেন</p>
        </div>
        <div className="bg-blue-50/60 p-4 rounded-2xl border border-blue-100">
          <p className="text-2xl md:text-3xl font-bold text-blue-600">
            ৳ {received.toLocaleString('bn-BD')}
          </p>
          <p className="text-sm text-gray-600 mt-1 font-medium">পেয়েছেন</p>
        </div>
      </div>

      {(member.phone || member.address) && (
        <div className="text-sm md:text-base text-gray-600 space-y-2 mt-4">
          {member.phone && (
            <p className="flex items-center justify-center gap-2">
              <span className="text-emerald-600">☎</span> {member.phone}
            </p>
          )}
          {member.address && (
            <p className="flex items-center justify-center gap-2">
              <span className="text-blue-600">📍</span> {member.address}
            </p>
          )}
        </div>
      )}
    </div>
  );
}